import React, { useState, useCallback, useRef, useEffect } from 'react';
import { SuggestionType, Companion, ChatMessage } from '../types';
import { getAiSuggestion, getRhymes } from '../services/geminiService';
import { GoogleGenAI, Chat } from "@google/genai";
import LyricEditor from './LyricEditor';
import SuggestionControls from './SuggestionControls';
import SuggestionDisplay from './SuggestionDisplay';
import ChatView from './ChatView';
import CompanionSelector from './CompanionSelector';
import RhymeBox from './RhymeBox';
import { companions } from '../companions';
import { BackArrowIcon } from './icons/BackArrowIcon';
import { PencilIcon } from './icons/PencilIcon';
import { ChatBubbleIcon } from './icons/ChatBubbleIcon';
import { UsersIcon } from './icons/UsersIcon';

interface WorkspaceProps {
    onBack: () => void;
}

const LOCAL_STORAGE_KEY = 'songcraft-song-data-v2';

const Workspace: React.FC<WorkspaceProps> = ({ onBack }) => {
    // Core editor state
    const [lyrics, setLyrics] = useState<string>('');
    const [suggestion, setSuggestion] = useState<string>('');
    const [isSuggestionLoading, setIsSuggestionLoading] = useState<boolean>(false);
    const [suggestionError, setSuggestionError] = useState<string | null>(null);

    // View state
    const [activeTab, setActiveTab] = useState<'editor' | 'chat'>('editor');

    // Companion and chat state
    const [companion, setCompanion] = useState<Companion>(companions[0]);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [isChatLoading, setIsChatLoading] = useState<boolean>(false);
    const [isCompanionSelectorOpen, setIsCompanionSelectorOpen] = useState(false);
    const chatRef = useRef<Chat | null>(null);

    // Rhyme finder state
    const [rhymeState, setRhymeState] = useState({ isOpen: false, word: '', rhymes: [], isLoading: false, error: null as string | null });


    // Load saved data on initial render
    useEffect(() => {
        try {
            const savedDataJSON = localStorage.getItem(LOCAL_STORAGE_KEY);
            if (savedDataJSON) {
                const savedData = JSON.parse(savedDataJSON);
                if (savedData.lyrics) setLyrics(savedData.lyrics);
                if (savedData.suggestion) setSuggestion(savedData.suggestion);
                if (savedData.companion) setCompanion(savedData.companion);
                if (savedData.messages) setMessages(savedData.messages);
                if (savedData.activeTab) setActiveTab(savedData.activeTab);
            } else {
                 setMessages([{ sender: 'greeting', content: companion.greeting }]);
            }
        } catch (e) {
            console.error("Failed to parse saved song data:", e);
        }
    }, []);

    // Auto-save data to local storage
    const saveData = useCallback(() => {
        try {
            const songData = { lyrics, suggestion, companion, messages, activeTab };
            localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(songData));
        } catch (error) {
            console.error("Failed to save song data:", error);
        }
    }, [lyrics, suggestion, companion, messages, activeTab]);

    // Initialize chat session when companion changes
    useEffect(() => {
        if (!process.env.API_KEY) return;
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const chatHistory = messages
            .filter(m => m.sender !== 'greeting')
            .map(msg => ({
                role: msg.sender === 'user' ? 'user' : 'model',
                parts: [{ text: msg.content }]
            }));

        chatRef.current = ai.chats.create({
            model: 'gemini-2.5-pro',
            config: { systemInstruction: companion.systemInstruction },
            history: chatHistory,
        });
    }, [companion, messages]);

    const handleRhymeRequest = async () => {
        const lastWord = lyrics.trim().split(/[\s\n]+/).pop()?.replace(/[.,!?]/g, '');
        if (!lastWord) {
            setSuggestionError('Write something to find rhymes for the last word.');
            return;
        }
        setRhymeState({ isOpen: true, word: lastWord, rhymes: [], isLoading: true, error: null });
        try {
            const rhymes = await getRhymes(lastWord);
            setRhymeState(prev => ({ ...prev, rhymes, isLoading: false }));
        } catch (e: any) {
            setRhymeState(prev => ({...prev, error: e.message, isLoading: false }));
        }
    };

    const handleSelectRhyme = (rhyme: string) => {
        setLyrics(prev => {
            const lastSpaceIndex = prev.trimEnd().lastIndexOf(' ');
            const newLyrics = lastSpaceIndex === -1 
                ? rhyme 
                : `${prev.substring(0, lastSpaceIndex)} ${rhyme}`;
            return newLyrics + ' ';
        });
    };

    const handleSuggestionRequest = useCallback(async (type: SuggestionType) => {
        if (type === SuggestionType.RHYMES) {
            handleRhymeRequest();
            return;
        }
        if (!lyrics.trim()) {
            setSuggestionError('Please enter some lyrics or record your voice first.');
            return;
        }
        setIsSuggestionLoading(true);
        setSuggestionError(null);
        setSuggestion('');
        const result = await getAiSuggestion(lyrics, type);

        if (result.toLowerCase().includes('error occurred')) {
            setSuggestionError(result);
        } else {
            setSuggestion(result);
        }
        setIsSuggestionLoading(false);
    }, [lyrics]);

    const handleSendMessage = async (messageText: string) => {
        setIsChatLoading(true);
        const userMessage: ChatMessage = { sender: 'user', content: messageText };
        setMessages(prev => [...prev, userMessage]);

        if (!chatRef.current) {
            console.error("Chat not initialized");
            setIsChatLoading(false);
            return;
        }

        try {
            const response = await chatRef.current.sendMessage({ message: messageText });
            const companionMessage: ChatMessage = { sender: 'companion', content: response.text };
            setMessages(prev => [...prev, companionMessage]);
        } catch (error) {
            console.error("Error sending chat message:", error);
            const errorMessage: ChatMessage = { sender: 'companion', content: "Sorry, I encountered an error. Please try again." };
            setMessages(prev => [...prev, errorMessage]);
        }
        setIsChatLoading(false);
    };

    const handleCompanionSelect = (newCompanion: Companion) => {
        setCompanion(newCompanion);
        setMessages([{ sender: 'greeting', content: newCompanion.greeting }]);
    };

    const handleTranscriptUpdate = (transcript: string) => {
        setLyrics(prev => `${prev}${prev ? ' ' : ''}${transcript}`);
    };

    return (
        <div className="max-w-4xl mx-auto p-4 flex flex-col gap-6">
            {isCompanionSelectorOpen && (
                <CompanionSelector
                    companions={companions}
                    selectedCompanion={companion}
                    onSelect={handleCompanionSelect}
                    onClose={() => setIsCompanionSelectorOpen(false)}
                />
            )}
            {rhymeState.isOpen && (
                <RhymeBox
                    {...rhymeState}
                    onSelectRhyme={handleSelectRhyme}
                    onClose={() => setRhymeState(prev => ({...prev, isOpen: false}))}
                />
            )}

            <header className="flex items-center w-full gap-2">
                <button onClick={onBack} className="p-2 rounded-full hover:bg-white/10 transition-colors" aria-label="Go back">
                    <BackArrowIcon className="w-6 h-6 text-gray-300"/>
                </button>
                <div className="mx-auto bg-white/5 p-1 rounded-full flex items-center gap-1">
                    <TabButton icon={<PencilIcon className="w-5 h-5"/>} text="Song Editor" isActive={activeTab === 'editor'} onClick={() => setActiveTab('editor')} />
                    <TabButton icon={<ChatBubbleIcon className="w-5 h-5"/>} text={`Chat with ${companion.name}`} isActive={activeTab === 'chat'} onClick={() => setActiveTab('chat')} />
                </div>
                <button onClick={() => setIsCompanionSelectorOpen(true)} className="p-2 rounded-full hover:bg-white/10 transition-colors" aria-label="Change companion">
                     <UsersIcon className="w-6 h-6"/>
                </button>
            </header>

            <main className="w-full flex flex-col gap-6">
                {activeTab === 'editor' ? (
                    <>
                        <LyricEditor 
                            value={lyrics} 
                            onChange={(e) => setLyrics(e.target.value)}
                            onTranscriptUpdate={handleTranscriptUpdate}
                            onSave={saveData}
                        />
                        <SuggestionControls onSuggestionSelect={handleSuggestionRequest} isLoading={isSuggestionLoading} />
                        <SuggestionDisplay suggestion={suggestion} isLoading={isSuggestionLoading} error={suggestionError} />
                    </>
                ) : (
                    <ChatView 
                        messages={messages}
                        onSendMessage={handleSendMessage}
                        isLoading={isChatLoading}
                        companionName={companion.name}
                    />
                )}
            </main>
        </div>
    );
};

const TabButton: React.FC<{icon: React.ReactNode, text: string, isActive: boolean, onClick: () => void}> = ({icon, text, isActive, onClick}) => (
    <button
        onClick={onClick}
        className={`px-3 py-2 text-sm sm:px-4 sm:py-2 sm:text-base font-semibold rounded-full flex items-center gap-2 transition-colors ${
            isActive ? 'bg-purple-600 text-white' : 'text-gray-300 hover:bg-white/10'
        }`}
    >
        {icon}
        <span className="hidden sm:inline">{text}</span>
    </button>
);


export default Workspace;

