import React, { useState, useEffect } from 'react';
import { Project, Companion } from '../types';
import { companions } from '../companions';
import { PlusIcon } from './icons/PlusIcon';
import { TrashIcon } from './icons/TrashIcon';
import { MusicNoteIcon } from './icons/MusicNoteIcon';

interface ProjectListProps {
  onSelectProject: (projectId: string) => void;
}

const PROJECTS_STORAGE_KEY = 'songcraft-projects';
const OLD_STORAGE_KEY = 'songcraft-song-data-v2';

const ProjectList: React.FC<ProjectListProps> = ({ onSelectProject }) => {
  const [projects, setProjects] = useState<Project[]>([]);

  useEffect(() => {
    // Load projects or migrate old data
    const loadProjects = () => {
      try {
        const storedProjects = localStorage.getItem(PROJECTS_STORAGE_KEY);
        if (storedProjects) {
          setProjects(JSON.parse(storedProjects));
        } else {
          // Migration check
          const oldDataJSON = localStorage.getItem(OLD_STORAGE_KEY);
          if (oldDataJSON) {
            const oldData = JSON.parse(oldDataJSON);
            const migratedProject: Project = {
              id: crypto.randomUUID(),
              title: 'My First Song (Migrated)',
              lastModified: Date.now(),
              lyrics: oldData.lyrics || '',
              suggestion: oldData.suggestion || '',
              companion: oldData.companion || companions[0],
              messages: oldData.messages || [],
              activeTab: oldData.activeTab || 'editor'
            };
            const newProjects = [migratedProject];
            setProjects(newProjects);
            localStorage.setItem(PROJECTS_STORAGE_KEY, JSON.stringify(newProjects));
            // Optional: localStorage.removeItem(OLD_STORAGE_KEY);
          }
        }
      } catch (e) {
        console.error("Error loading projects:", e);
      }
    };
    loadProjects();
  }, []);

  const handleCreateProject = () => {
    const newProject: Project = {
      id: crypto.randomUUID(),
      title: 'Untitled Song',
      lastModified: Date.now(),
      lyrics: '',
      suggestion: '',
      companion: companions[0],
      messages: [{ sender: 'greeting', content: companions[0].greeting }],
      activeTab: 'editor'
    };

    const updatedProjects = [newProject, ...projects];
    setProjects(updatedProjects);
    localStorage.setItem(PROJECTS_STORAGE_KEY, JSON.stringify(updatedProjects));
    onSelectProject(newProject.id);
  };

  const handleDeleteProject = (e: React.MouseEvent, projectId: string) => {
    e.stopPropagation();
    if (window.confirm('Are you sure you want to delete this song?')) {
      const updatedProjects = projects.filter(p => p.id !== projectId);
      setProjects(updatedProjects);
      localStorage.setItem(PROJECTS_STORAGE_KEY, JSON.stringify(updatedProjects));
    }
  };

  const formatDate = (timestamp: number) => {
    return new Date(timestamp).toLocaleDateString(undefined, {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  return (
    <div className="max-w-6xl mx-auto p-6">
      <div className="mb-8 text-center sm:text-left">
        <h1 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-500 mb-2">
          Your Projects
        </h1>
        <p className="text-gray-400">Manage your songs and creative ideas</p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {/* Create New Card */}
        <button
          onClick={handleCreateProject}
          className="group flex flex-col items-center justify-center p-8 bg-white/5 border-2 border-dashed border-gray-700 rounded-2xl hover:border-purple-500 hover:bg-white/10 transition-all duration-300 min-h-[200px]"
        >
          <div className="p-4 bg-purple-600 rounded-full mb-4 group-hover:scale-110 transition-transform">
            <PlusIcon className="w-8 h-8 text-white" />
          </div>
          <span className="text-xl font-semibold text-gray-200">Create New Song</span>
        </button>

        {/* Project Cards */}
        {projects.map((project) => (
          <div
            key={project.id}
            onClick={() => onSelectProject(project.id)}
            className="group relative flex flex-col p-6 bg-[#2a1d43] rounded-2xl border border-gray-700 hover:border-purple-500 hover:shadow-xl transition-all duration-300 cursor-pointer min-h-[200px]"
          >
            <div className="flex-grow">
                <div className="flex items-start justify-between mb-4">
                    <div className="p-3 bg-purple-900/50 rounded-lg text-purple-300">
                        <MusicNoteIcon className="w-6 h-6" />
                    </div>
                    <button
                        onClick={(e) => handleDeleteProject(e, project.id)}
                        className="p-2 text-gray-500 hover:text-red-400 hover:bg-white/5 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                        aria-label="Delete project"
                    >
                        <TrashIcon className="w-5 h-5" />
                    </button>
                </div>
                <h3 className="text-xl font-bold text-white mb-2 line-clamp-1" title={project.title}>
                    {project.title}
                </h3>
                <p className="text-sm text-gray-400 line-clamp-2">
                    {project.lyrics ? project.lyrics.substring(0, 60) + "..." : "No lyrics yet"}
                </p>
            </div>
            <div className="pt-4 mt-4 border-t border-gray-700 flex items-center justify-between text-xs text-gray-500">
                <span>{project.companion.name}</span>
                <span>Edited {formatDate(project.lastModified)}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

